def apply():
    import json
    from pathlib import Path

    scripts = Path(__file__).resolve().parent
    path = scripts / "loc_chunk_0_full.json"
    data = json.loads(path.read_text(encoding="utf-8"))
    if len(ROWS) != 192:
        raise SystemExit(f"Expected 192 translation rows, got {len(ROWS)}")
    if len(data) != 192:
        raise SystemExit(f"Expected 192 entries in JSON, got {len(data)}")

    for i, entry in enumerate(data):
        row = ROWS[i]
        if len(row) != len(NEW_LANGS):
            raise SystemExit(f"Row {i} has {len(row)} langs, expected {len(NEW_LANGS)}")
        for lang, text in zip(NEW_LANGS, row):
            entry[lang] = text

    # Reorder keys: existing langs, then new langs, then section
    base_order = ["en", "ja", "de", "es", "fr", "it", "nl", "pt", "ru", "zh", "ko"]
    out = []
    for entry in data:
        ordered = {k: entry[k] for k in base_order}
        for lang in NEW_LANGS:
            ordered[lang] = entry[lang]
        if "section" in entry:
            ordered["section"] = entry["section"]
        out.append(ordered)

    path.write_text(json.dumps(out, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    print(f"Updated {len(out)} entries in {path}")


if __name__ == "__main__":
    apply()
